SELECT fa.id, fa.apply_no AS applyNo, fa.apply_type AS applyType,
       fa.title, fa.reason, fa.duration_hours AS durationHours,
       fa.status, fa.approver_id AS approverId,
       fa.start_time AS startTime, fa.end_time AS endTime,
       fa.created_at AS createdAt
FROM flow_apply fa
WHERE fa.applicant_id = #{userId} AND fa.is_deleted = 0

    AND fa.apply_type = #{dto.applyType}


    AND fa.status = #{dto.status}


    AND fa.created_at >= #{dto.startDate}


    AND fa.created_at <= #{dto.endDate}

ORDER BY fa.created_at DESC
LIMIT #{dto.pageSize} OFFSET #{dto.offset}

SELECT COUNT(*)
FROM flow_apply fa
WHERE fa.applicant_id = #{userId} AND fa.is_deleted = 0

    AND fa.apply_type = #{dto.applyType}


    AND fa.status = #{dto.status}


    AND fa.created_at >= #{dto.startDate}


    AND fa.created_at <= #{dto.endDate}

SELECT fa.id, fa.apply_no AS applyNo, fa.apply_type AS applyType,
       fa.title, fa.reason, fa.duration_hours AS durationHours,
       fa.applicant_id AS applicantId, fa.applicant_dept_id AS applicantDeptId,
       fa.start_time AS startTime, fa.end_time AS endTime,
       fa.created_at AS createdAt
FROM flow_apply fa
WHERE fa.approver_id = #{approverId}
  AND fa.status = 'PENDING'
  AND fa.is_deleted = 0

    AND fa.applicant_dept_id = #{deptId}


    AND fa.apply_type = #{dto.applyType}

ORDER BY fa.created_at DESC
LIMIT #{dto.pageSize} OFFSET #{dto.offset}

SELECT COUNT(*)
FROM flow_apply fa
WHERE fa.approver_id = #{approverId}
  AND fa.status = 'PENDING'
  AND fa.is_deleted = 0

    AND fa.applicant_dept_id = #{deptId}


    AND fa.apply_type = #{dto.applyType}

SELECT fa.id, fa.apply_no AS applyNo, fa.apply_type AS applyType, fa.title, fa.status, fa.applicant_id AS applicantId, far.action AS myAction, far.approved_at AS approvedAt, fa.created_at AS createdAt FROM flow_apply fa INNER JOIN flow_approve_record far ON far.flow_apply_id = fa.id AND far.approver_id = #{approverId} AND far.action IN ('APPROVE', 'REJECT') WHERE fa.is_deleted = 0
AND fa.applicant_dept_id = #{deptId}
AND fa.apply_type = #{dto.applyType}
ORDER BY far.approved_at DESC LIMIT #{dto.pageSize} OFFSET #{dto.offset}

SELECT COUNT(*)
FROM flow_apply fa
INNER JOIN flow_approve_record far ON far.flow_apply_id = fa.id
    AND far.approver_id = #{approverId}
    AND far.action IN ('APPROVE', 'REJECT')
WHERE fa.is_deleted = 0

    AND fa.applicant_dept_id = #{deptId}


    AND fa.apply_type = #{dto.applyType}

SELECT fa.id, fa.apply_no AS applyNo, fa.apply_type AS applyType,
       fa.title, fa.reason, fa.duration_hours AS durationHours,
       fa.applicant_id AS applicantId, fa.applicant_dept_id AS applicantDeptId,
       fa.approver_id AS approverId,
       fa.start_time AS startTime, fa.end_time AS endTime,
       fa.approved_at AS approvedAt, fa.created_at AS createdAt
FROM flow_apply fa
WHERE fa.status = 'APPROVED'
  AND fa.is_deleted = 0

    AND fa.applicant_dept_id = #{deptId}


    AND fa.apply_type = #{dto.applyType}


    AND fa.approved_at >= #{dto.startDate}


    AND fa.approved_at <= #{dto.endDate}

ORDER BY fa.approved_at DESC
LIMIT #{dto.pageSize} OFFSET #{dto.offset}

SELECT COUNT(*)
FROM flow_apply fa
WHERE fa.status = 'APPROVED'
